// html2pdf.js — version locale PWA
// Cette version utilise window.print() comme fallback si le PDF CDN n'est pas disponible
(function(global){
  if(typeof global.html2pdf !== 'undefined') return; // Already loaded
  
  function Html2Pdf() {
    this._opt = {};
    this._from_el = null;
  }
  
  Html2Pdf.prototype.set = function(opt) { this._opt = opt; return this; };
  Html2Pdf.prototype.from = function(el) { this._from_el = el; return this; };
  Html2Pdf.prototype.save = function() {
    var self = this;
    return new Promise(function(resolve, reject) {
      // Try to load from CDN dynamically
      var script = document.createElement('script');
      script.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js';
      script.onload = function() {
        // CDN loaded, use real library
        try {
          html2pdf().set(self._opt).from(self._from_el).save().then(resolve).catch(reject);
        } catch(e) { reject(e); }
      };
      script.onerror = function() {
        // Offline — use print
        if(confirm('📄 Mode hors ligne : la génération PDF nécessite internet.\n\nUtiliser l\'impression du navigateur à la place ?')) {
          window.print();
          resolve();
        } else {
          reject(new Error('PDF non disponible hors ligne'));
        }
      };
      document.head.appendChild(script);
    });
  };
  
  global.html2pdf = function() { return new Html2Pdf(); };
})(window);
